member.example:
Bind the AudioSource dopplerLevel property using a serialized binder field — the target AudioSource is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private AudioSourceDopplerLevelBinder _dopplerLevel;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _dopplerLevel;
    }


Bind the AudioSource dopplerLevel property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private AudioSource _audioSource;
        
        private AudioSourceDopplerLevelBinder DopplerLevel =>
            new(_audioSource);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _dopplerLevel;
    }

Switch the AudioSource dopplerLevel between two values using a serialized binder field — the target AudioSource is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private AudioSourceDopplerLevelSwitcherBinder _isMoving;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isMoving;
    }


Switch the AudioSource dopplerLevel between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] 
        private AudioSource _audioSource;
        
        [SerializeField] 
        private float _trueLevel;
        
        [SerializeField] 
        private float _falseLevel;
        
        private AudioSourceDopplerLevelSwitcherBinder IsMoving => new(
            _audioSource, _trueLevel, _falseLevel);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isMoving;
    }
